 {"id":"bd-v5mp","title":"syscall: mount_setattr empty-string pathname should preserve unprivileged EPERM host contract","description":"On the current host, unprivileged mount_setattr(AT_FDCWD, \"\", 0, &attr, sizeof(attr)) and the AT_EMPTY_PATH variant both fail with EPERM. Add focused ABI parity coverage so future wrapper changes keep that privilege-path behavior explicit.","status":"closed","priority":2,"issue_type":"task","created_at":"2026-04-21T07:37:58.915535729Z","created_by":"AmberSignal","updated_at":"2026-04-21T20:58:07.359911625Z","closed_at":"2026-04-21T20:58:07.357739424Z","close_reason":"done","source_repo":".","compaction_level":0,"original_size":0}
 {"id":"bd-v6m7","title":"syscall: process_madvise edge-case errno matrix should match host exactly","description":"Host glibc exposes a stable errno matrix for process_madvise edge cases: NULL iov with nonzero len => EFAULT, NULL iov with zero len and invalid pidfd => EBADF, invalid flags => EINVAL. Add focused ABI tests and tighten any implementation mismatch exposed by those probes.","status":"closed","priority":2,"issue_type":"task","created_at":"2026-04-21T07:03:07.826864192Z","created_by":"ubuntu","updated_at":"2026-04-21T19:21:27.220722952Z","closed_at":"2026-04-21T19:21:27.218464437Z","close_reason":"Pinned process_madvise edge-case errno matrix to exact host EFAULT/EBADF/EINVAL parity","source_repo":".","compaction_level":0,"original_size":0}
